{
  "name": "Senior Medicare Patrol (SMP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, families, and caregivers regardless of income[1][2][3]",
    "asset_limits": "No asset limits or tests apply[1][2][3]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver with concerns about potential Medicare fraud, errors, or abuse[1][2][3]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Outreach and education on Medicare fraud prevention; one-on-one counseling; assistance resolving billing disputes; referrals to state/federal agencies for suspected fraud investigations; free presentations and community events; volunteer-led support[1][2][3]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-726-2916 (Arkansas SMP)[2]", "Email: [email protected][2]", "Contact local SMP via SMP Locator at smpresource.org (national tool to find Arkansas program)[1]"],
    "processing_time": "Immediate assistance for counseling and referrals; no formal application processing as it's education/outreach-based[1][2][3]",
    "waitlist": null,
    "forms": ["No specific application forms required; SHIIP/MIPPA Application mentioned for related volunteering but not for services[2]"],
    "documents": ["Medicare Summary Notice (MSN) or billing statements if addressing specific fraud/error concerns; Medicare card if requesting 1-800-MEDICARE support[2][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Arkansas Medicare beneficiaries[2][4]",
    "regional_variations": "Administered statewide by Arkansas Insurance Department and formerly DHS Division of Aging and Adult Services; local volunteers may serve specific areas but no differing eligibility, benefits, or wait times noted[2][4]",
    "offices_or_providers": ["Arkansas Insurance Department (statewide contact); local SMP teams via SMP Locator[1][2]"]
  },
  "official_source": "https://insurance.arkansas.gov/consumer-assistance/senior-medicare-patrol-smp/",
  "gotchas": ["Not a financial aid or healthcare service program—focuses solely on fraud prevention, education, and reporting, not direct medical or monetary benefits[1][3]", "Many programs co-locate with SHIP for insurance counseling, which may confuse it with benefit enrollment help[1][2]", "Requires active engagement like reviewing MSNs or reporting suspicions; passive eligibility doesn't provide ongoing services[5]", "Primarily volunteer-driven, so availability may depend on local team capacity[3][4]"],
  "data_shape_notes": "no income test; volunteer-based education and advocacy only; open to all Medicare beneficiaries/families without application barriers; often bundled with SHIP counseling"
}

{
  "name": "Family Caregiver Support Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No income restrictions[1][3]",
    "asset_limits": "No asset limits mentioned; not applicable[1]",
    "other_requirements": ["Care recipient must be at least 60 years old (no age limit if Alzheimer's or related dementia)[1][3]", "Caregiver must assist with activities like transportation, housework, meals, medication reminders, medical appointments, finances, dressing, or managing chronic conditions[1]", "Some local grants require specific diagnosis, chronic illness certification by physician, or residence in service area (e.g., Pulaski, Saline, Monroe, Prairie, Lonoke, Faulkner counties for CareLink)[5]", "Care recipient cannot receive duplicate services from other sources like Medicaid, Medicare, ARChoices, etc.[5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Respite grants for services like respite care, counseling, training, access to assistance; specific services vary by local grant (e.g., home care, day care, facility care); no fixed dollar amounts or hours statewide, provided at no cost to families[1][3][5][8]",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging for specific grants and application details[3]", "For CareLink example: Apply through Alzheimer’s Arkansas Programs and Services, 201 Markham Center Drive, Little Rock AR 72205 (4-step process including physician certification)[5]", "No statewide online URL, phone, or form specified; use agingarkansas.org for general info[1][3]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Varies by local grant; e.g., 2018-2019 CL-Grant Application for specific areas[5]"],
    "documents": ["Physician certification of chronic illness (for some grants)[5]", "Proof of care activities and non-duplication of services[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered locally through Area Agencies on Aging; some grants county-specific (e.g., Pulaski, Saline, Monroe, Prairie, Lonoke, Faulkner)[3][5]",
    "regional_variations": "Eligibility, services, and requirements vary by local grant and Area Agency on Aging; different providers like Alzheimer’s Arkansas for central AR[3][5]",
    "offices_or_providers": ["Local Area Agency on Aging[3]", "Alzheimer’s Arkansas Programs and Services (Little Rock)[5]"]
  },
  "official_source": "https://agingarkansas.org/services/family-caregiver-support/[1]",
  "gotchas": ["Not all grants are identical; contact local Area Agency on Aging for exact requirements as they vary[3]", "No duplicate services allowed from other funding sources[5]", "VA program is separate and for veterans only[2]", "Confused with Medicaid paid caregiver programs like Arkansas Independent Choices, which have income/asset limits[7][10]"],
  "data_shape_notes": "Administered via local Area Agencies on Aging with varying grant-specific rules; no statewide income test or fixed benefits; some county-restricted"
}

{
  "name": "Long-Term Care Ombudsman",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all long-term care facility residents regardless of financial status[5][6]",
    "asset_limits": "No asset limits; no financial tests apply[5][6]",
    "other_requirements": ["Must be a resident of a long-term care facility (e.g., nursing home, assisted living) in Arkansas[1][5][6]", "No relation to facility residents or staff for volunteer advocates, but residents themselves have no such restriction[1][8]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including investigating and resolving complaints on resident rights, quality of life, Medicaid/Medicare issues, discharges/transfers, finances, food quality, room temperature, social activities, care plans, restraints, guardianship/power of attorney; education on rights; referrals and follow-through on solutions; reporting unresolved grievances to regional ombudsman[1][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact local ombudsman (number posted in facility) or regional Area Agency on Aging[5]", "In-person: Visit local long-term care facility ombudsman contact or Area Agency on Aging office[1][5]", "Anyone (family, friends, staff, residents, anonymous) can contact directly with concerns; no formal application for services[5][6]"],
    "processing_time": "Immediate response encouraged; no specified formal processing time as it's complaint-driven[1][5]",
    "waitlist": null,
    "forms": ["No specific forms required for receiving services; training forms only for volunteers[1][2]"],
    "documents": ["No documents needed to request services; provide details of concern (e.g., resident name, facility, issue description)[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in long-term care facilities across Arkansas; access via regional offices[3][5]",
    "regional_variations": "Training varies slightly by region; delivered through 9 Area Agencies on Aging covering different regions; regional ombudsmen handle local facilities[1][2][4]",
    "offices_or_providers": ["Area Agencies on Aging (AAA) in each region; contact local AAA or facility-posted ombudsman[1][5]"]
  },
  "official_source": "https://aging.arkansas.gov/programs-services/long-term-care-ombudsman-program/",
  "gotchas": ["Not a direct service provider or financial aid program—purely advocacy and complaint resolution; no healthcare or housing services[5][6]", "Volunteers must be 18+, no conflicts of interest, complete training—families cannot 'apply' to become ombudsman without certification[1][8]", "Anyone can contact, including anonymously; call for any concern, not just emergencies[5]", "Facilities must allow access; denial escalates to state level[2]"],
  "data_shape_notes": "no income test; complaint-driven advocacy for all LTC residents statewide via regional AAAs; volunteer-based with certification requirements; not a benefits program with limits or waitlists"
}
